#!/usr/bin/env node
/**
 * Chinese LLM Router - Core Router
 * Routes chat completions to configured Chinese LLM providers
 * All providers use OpenAI-compatible API format
 */

const fs = require('fs');
const path = require('path');
const https = require('https');
const http = require('http');

const CONFIG_FILE = path.join(
  process.env.HOME || process.env.USERPROFILE,
  '.chinese-llm-router', 'config.json'
);

// Model → Provider mapping (auto-built from config)
const MODEL_ALIASES = {
  // DeepSeek
  'deepseek': 'deepseek-chat',
  'deepseek-v3': 'deepseek-chat',
  'deepseek-v3.2': 'deepseek-chat',
  'deepseek-r1': 'deepseek-reasoner',
  // Qwen
  'qwen': 'qwen3-max',
  'qwen3': 'qwen3-max',
  'qwen-thinking': 'qwen3-max-thinking',
  'qwen-coder': 'qwen3-coder-plus',
  'qwen-turbo': 'qwen-turbo-latest',
  // GLM
  'glm': 'glm-5',
  'zhipu': 'glm-5',
  'chatglm': 'glm-5',
  // Kimi
  'kimi': 'kimi-k2.5',
  'moonshot': 'kimi-k2.5',
  'kimi-thinking': 'kimi-k2.5-thinking',
  // Doubao
  'doubao': 'doubao-seed-2.0-pro',
  'doubao-pro': 'doubao-seed-2.0-pro',
  'doubao-lite': 'doubao-seed-2.0-lite',
  'doubao-mini': 'doubao-seed-2.0-mini',
  '豆包': 'doubao-seed-2.0-pro',
  // MiniMax
  'minimax': 'minimax-m2.5',
  // Step
  'step': 'step-3.5-flash',
  '阶跃': 'step-3.5-flash',
  // Baichuan
  'baichuan': 'baichuan4-turbo',
  '百川': 'baichuan4-turbo',
  // Spark
  'spark': 'spark-v4.0-ultra',
  '星火': 'spark-v4.0-ultra',
  // Hunyuan
  'hunyuan': 'hunyuan-turbo-s',
  '混元': 'hunyuan-turbo-s'
};

// Task → Model recommendations
const TASK_RECOMMENDATIONS = {
  'coding': ['glm-5', 'kimi-k2.5', 'qwen3-coder-plus', 'deepseek-chat'],
  'math': ['deepseek-reasoner', 'qwen3-max-thinking', 'kimi-k2.5-thinking'],
  'reasoning': ['deepseek-reasoner', 'qwen3-max-thinking', 'kimi-k2.5-thinking'],
  'writing': ['qwen3-max', 'doubao-seed-2.0-pro', 'kimi-k2.5'],
  'translation': ['qwen3-max', 'baichuan4-turbo', 'deepseek-chat'],
  'chat': ['qwen3-max', 'doubao-seed-2.0-pro', 'deepseek-chat'],
  'fast': ['step-3.5-flash', 'doubao-seed-2.0-mini', 'qwen-turbo-latest'],
  'cheap': ['deepseek-chat', 'doubao-seed-2.0-mini', 'step-3.5-flash'],
  'long': ['kimi-k2.5', 'deepseek-chat', 'qwen3-max'],
  'agent': ['glm-5', 'qwen3-max', 'doubao-seed-2.0-pro'],
  'vision': ['kimi-k2.5', 'qwen3-max', 'glm-5']
};

function loadConfig() {
  if (!fs.existsSync(CONFIG_FILE)) {
    throw new Error(`Config not found. Run: node scripts/setup.js`);
  }
  return JSON.parse(fs.readFileSync(CONFIG_FILE, 'utf8'));
}

function resolveModel(name) {
  const lower = name.toLowerCase().trim();
  return MODEL_ALIASES[lower] || lower;
}

function findProvider(config, modelId) {
  for (const [providerId, provider] of Object.entries(config.providers)) {
    if (provider.models.includes(modelId)) {
      return { providerId, ...provider };
    }
  }
  return null;
}

function chatCompletion(provider, model, messages, options = {}) {
  return new Promise((resolve, reject) => {
    const url = new URL(provider.baseUrl + '/chat/completions');
    const isHttps = url.protocol === 'https:';
    const client = isHttps ? https : http;

    const body = JSON.stringify({
      model,
      messages,
      temperature: options.temperature ?? 0.7,
      max_tokens: options.max_tokens ?? 4096,
      stream: options.stream ?? false,
      ...options.extra
    });

    const req = client.request({
      hostname: url.hostname,
      port: url.port || (isHttps ? 443 : 80),
      path: url.pathname + '/chat/completions',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${provider.apiKey}`,
        'Content-Length': Buffer.byteLength(body)
      }
    }, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) {
          reject(new Error(`${res.statusCode}: ${data}`));
        } else {
          try { resolve(JSON.parse(data)); }
          catch (e) { reject(new Error(`Parse error: ${data.slice(0, 200)}`)); }
        }
      });
    });

    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

async function route(modelName, messages, options = {}) {
  const config = loadConfig();
  const modelId = resolveModel(modelName);
  const provider = findProvider(config, modelId);

  if (!provider) {
    // Try fallback
    for (const fb of (config.fallback || [])) {
      const fbProvider = findProvider(config, fb);
      if (fbProvider) {
        console.warn(`⚠️ Model "${modelName}" not configured, falling back to ${fb}`);
        return chatCompletion(fbProvider, fb, messages, options);
      }
    }
    throw new Error(`Model "${modelName}" not found. Run: node scripts/setup.js`);
  }

  return chatCompletion(provider, modelId, messages, options);
}

function listModels() {
  const config = loadConfig();
  const result = [];
  for (const [id, provider] of Object.entries(config.providers)) {
    for (const model of provider.models) {
      result.push({ provider: id, model, baseUrl: provider.baseUrl });
    }
  }
  return result;
}

function recommend(task) {
  const config = loadConfig();
  const recs = TASK_RECOMMENDATIONS[task.toLowerCase()] || TASK_RECOMMENDATIONS['chat'];
  return recs.filter(m => findProvider(config, m)).map(m => ({
    model: m,
    provider: findProvider(config, m)?.providerId
  }));
}

// CLI mode
if (require.main === module) {
  const args = process.argv.slice(2);
  const cmd = args[0];

  if (cmd === 'list') {
    const models = listModels();
    console.log('\n🇨🇳 Available Chinese LLMs:\n');
    for (const m of models) {
      console.log(`  ${m.model} (${m.provider})`);
    }
    console.log(`\nTotal: ${models.length} models from ${new Set(models.map(m => m.provider)).size} providers`);
  } else if (cmd === 'recommend') {
    const task = args[1] || 'chat';
    const recs = recommend(task);
    console.log(`\n🎯 Recommended for "${task}":\n`);
    recs.forEach((r, i) => console.log(`  ${i + 1}. ${r.model} (${r.provider})`));
  } else if (cmd === 'test') {
    const model = args[1] || 'qwen3-max';
    console.log(`\n🧪 Testing ${model}...`);
    route(model, [{ role: 'user', content: '你好，请用一句话介绍你自己。' }])
      .then(r => {
        console.log(`✅ ${model}: ${r.choices[0].message.content}`);
        if (r.usage) console.log(`   Tokens: ${r.usage.prompt_tokens} in / ${r.usage.completion_tokens} out`);
      })
      .catch(e => console.error(`❌ ${model}: ${e.message}`));
  } else {
    console.log('Usage: node router.js <command>');
    console.log('  list              - List all configured models');
    console.log('  recommend <task>  - Get model recommendation (coding/math/writing/fast/cheap/...)');
    console.log('  test <model>      - Test a model with a simple prompt');
  }
}

module.exports = { route, listModels, recommend, resolveModel, MODEL_ALIASES, TASK_RECOMMENDATIONS };

#!/usr/bin/env node
/**
 * Chinese LLM Router - Interactive Setup
 * Guides user through configuring API keys for Chinese LLM providers
 */

const fs = require('fs');
const path = require('path');
const readline = require('readline');

const CONFIG_DIR = path.join(process.env.HOME || process.env.USERPROFILE, '.chinese-llm-router');
const CONFIG_FILE = path.join(CONFIG_DIR, 'config.json');

const PROVIDERS = [
  {
    id: 'deepseek',
    name: 'DeepSeek',
    baseUrl: 'https://api.deepseek.com/v1',
    models: ['deepseek-chat', 'deepseek-reasoner'],
    signup: 'https://platform.deepseek.com',
    desc: 'Best open-source, cheapest flagship model'
  },
  {
    id: 'qwen',
    name: 'Qwen (Alibaba/通义千问)',
    baseUrl: 'https://dashscope.aliyuncs.com/compatible-mode/v1',
    models: ['qwen3-max', 'qwen3-max-thinking', 'qwen3-coder-plus', 'qwen-turbo-latest'],
    signup: 'https://dashscope.console.aliyun.com',
    desc: 'Strong all-rounder, free tier available'
  },
  {
    id: 'glm',
    name: 'GLM (智谱AI)',
    baseUrl: 'https://open.bigmodel.cn/api/paas/v4',
    models: ['glm-5', 'glm-4-plus'],
    signup: 'https://open.bigmodel.cn',
    desc: 'Top coding & agent, just launched GLM-5'
  },
  {
    id: 'kimi',
    name: 'Kimi (月之暗面/Moonshot)',
    baseUrl: 'https://api.moonshot.cn/v1',
    models: ['kimi-k2.5', 'kimi-k2.5-thinking', 'moonshot-v1-128k'],
    signup: 'https://platform.moonshot.cn',
    desc: 'Great long context & vision, open source'
  },
  {
    id: 'doubao',
    name: 'Doubao Seed 2.0 (字节豆包)',
    baseUrl: 'https://ark.cn-beijing.volces.com/api/v3',
    models: ['doubao-seed-2.0-pro', 'doubao-seed-2.0-lite', 'doubao-seed-2.0-mini'],
    signup: 'https://console.volcengine.com/ark',
    desc: 'ByteDance, fast & cheap, just launched 2.0'
  },
  {
    id: 'minimax',
    name: 'MiniMax',
    baseUrl: 'https://api.minimax.chat/v1',
    models: ['minimax-m2.5'],
    signup: 'https://platform.minimaxi.com',
    desc: 'Lightweight powerhouse, can run locally'
  },
  {
    id: 'step',
    name: 'Step (阶跃星辰)',
    baseUrl: 'https://api.stepfun.com/v1',
    models: ['step-3.5-flash', 'step-2-16k'],
    signup: 'https://platform.stepfun.com',
    desc: 'Blazing fast inference, trending on OpenRouter'
  },
  {
    id: 'baichuan',
    name: 'Baichuan (百川)',
    baseUrl: 'https://api.baichuan-ai.com/v1',
    models: ['baichuan4-turbo'],
    signup: 'https://platform.baichuan-ai.com',
    desc: 'Strong Chinese language understanding'
  },
  {
    id: 'spark',
    name: 'Spark (讯飞星火)',
    baseUrl: 'https://spark-api-open.xf-yun.com/v1',
    models: ['spark-v4.0-ultra'],
    signup: 'https://console.xfyun.cn',
    desc: 'Speech & Chinese NLP specialist'
  },
  {
    id: 'hunyuan',
    name: 'Hunyuan (腾讯混元)',
    baseUrl: 'https://api.hunyuan.cloud.tencent.com/v1',
    models: ['hunyuan-turbo-s'],
    signup: 'https://cloud.tencent.com/product/hunyuan',
    desc: 'Tencent, WeChat ecosystem'
  }
];

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

function ask(question) {
  return new Promise(resolve => rl.question(question, resolve));
}

async function main() {
  console.log('\n🇨🇳 Chinese LLM Router - Setup\n');
  console.log('Configure API keys for Chinese AI models.');
  console.log('Skip any provider by pressing Enter.\n');

  // Load existing config
  let config = { providers: {}, default: 'qwen3-max', fallback: ['deepseek-chat'] };
  if (fs.existsSync(CONFIG_FILE)) {
    try {
      config = JSON.parse(fs.readFileSync(CONFIG_FILE, 'utf8'));
      console.log('Found existing config. Will update.\n');
    } catch (e) { /* ignore */ }
  }

  for (const provider of PROVIDERS) {
    const existing = config.providers[provider.id]?.apiKey;
    const hint = existing ? ` [current: ${existing.slice(0, 8)}...]` : '';
    console.log(`\n--- ${provider.name} ---`);
    console.log(`  ${provider.desc}`);
    console.log(`  Models: ${provider.models.join(', ')}`);
    console.log(`  Sign up: ${provider.signup}`);

    const key = await ask(`  API Key${hint}: `);
    if (key.trim()) {
      config.providers[provider.id] = {
        apiKey: key.trim(),
        baseUrl: provider.baseUrl,
        models: provider.models
      };
    } else if (existing) {
      console.log('  (keeping existing key)');
    } else {
      console.log('  (skipped)');
    }
  }

  // Choose default
  const configured = Object.keys(config.providers);
  if (configured.length > 0) {
    console.log(`\nConfigured providers: ${configured.join(', ')}`);
    const allModels = configured.flatMap(p => config.providers[p].models);
    console.log(`Available models: ${allModels.join(', ')}`);
    const def = await ask(`\nDefault model [${config.default}]: `);
    if (def.trim()) config.default = def.trim();

    const fb = await ask(`Fallback model(s), comma-separated [${config.fallback.join(',')}]: `);
    if (fb.trim()) config.fallback = fb.trim().split(',').map(s => s.trim());
  }

  // Save
  if (!fs.existsSync(CONFIG_DIR)) fs.mkdirSync(CONFIG_DIR, { recursive: true });
  fs.writeFileSync(CONFIG_FILE, JSON.stringify(config, null, 2));
  console.log(`\n✅ Config saved to ${CONFIG_FILE}`);
  console.log(`\nConfigured ${configured.length} provider(s). Your OpenClaw can now use Chinese LLMs!`);

  rl.close();
}

main().catch(err => {
  console.error('Setup failed:', err);
  rl.close();
  process.exit(1);
});

# Chinese LLM API Reference

All major Chinese LLM providers support OpenAI-compatible chat/completions API.

## Provider Endpoints (Feb 2026)

### DeepSeek (深度求索)
- Base URL: `https://api.deepseek.com/v1`
- Models: `deepseek-chat` (V3.2), `deepseek-reasoner` (R1)
- Context: 1M tokens (V3.2), 64K (R1)
- Pricing: Input ¥0.5/M, Output ¥2.0/M (cheapest flagship)
- Free tier: ¥10 credits on signup
- Docs: https://api-docs.deepseek.com

### Qwen / 通义千问 (Alibaba)
- Base URL: `https://dashscope.aliyuncs.com/compatible-mode/v1`
- Models: `qwen3-max`, `qwen3-max-thinking`, `qwen3-coder-plus`, `qwen-turbo-latest`
- Context: 128K (Max), 32K (Turbo)
- Pricing: Input ¥2.0/M, Output ¥6.0/M (Max); ¥0.3/¥0.6 (Turbo)
- Free tier: 1M tokens/month
- Docs: https://help.aliyun.com/zh/model-studio

### GLM (智谱AI)
- Base URL: `https://open.bigmodel.cn/api/paas/v4`
- Models: `glm-5` (NEW! 744B MoE), `glm-4-plus`
- Context: 128K
- Pricing: Input ¥5.0/M, Output ¥5.0/M (GLM-5, may change)
- Note: GLM-5 just launched 2026-02-11, pricing may adjust
- Docs: https://docs.bigmodel.cn

### Kimi (月之暗面/Moonshot AI)
