# OpenClaw 1Panel

## Overview

Use this skill to interact with a 1Panel instance through authenticated HTTP API calls. The bundled resources are TypeScript source files grouped by module, with query-oriented actions implemented now and mutation endpoints reserved for later expansion.

## Requirements

- Require a 1Panel API key with access to the target instance.
- Require these environment variables when executing the TypeScript resources in an OpenClaw runtime:
  - `ONEPANEL_BASE_URL`
  - `ONEPANEL_API_KEY`
  - optional: `ONEPANEL_TIMEOUT_MS`
  - optional: `ONEPANEL_SKIP_TLS_VERIFY=true`

## Workflow

1. Choose the module that matches the user's request.
2. Start with a list or search action to identify the exact target.
3. Read detail, status, or logs only after the target is confirmed.
4. If the user asks for create, update, delete, restart, stop, or any other mutation:
   - do not fabricate or guess a write workflow
   - surface the matching reserved mutation endpoint from the module
   - implement the write path only when that behavior is intentionally added to the skill

## Module Groups

- `monitoring`
  Resource monitoring, dashboard current status, top processes, historical monitor data, GPU history.
- `websites`
  Website list/detail, Nginx config reads, domain list, HTTPS config, SSL certificate reads, website log reads.
- `apps`
  App catalog lookup, installed app list, installed app detail, service list, port/connection info.
- `containers`
  Container list/status/detail, inspect, stats, streaming log reads.
- `logs`
  Operation logs, login logs, system log file list, generic line-by-line log reads.
- `cronjobs`
  Cronjob list/detail, next execution preview, execution records, record log reads.
- `task-center`
  1Panel task-center list and executing count.
- `nodes`
  Node list, simple node list, node options, node summary. Some endpoints may require Pro/XPack.

## Resources

- [references/module-groups.md](references/module-groups.md)
  Human-readable overview of module boundaries, common entrypoints, and reserved write scope.
- [scripts/client.ts](scripts/client.ts)
  Shared authenticated 1Panel client.
- [scripts/cli.ts](scripts/cli.ts)
  Executable CLI entry for OpenClaw or shell-based tool calls.
- [scripts/index.ts](scripts/index.ts)
  Registry of all module definitions.
- `scripts/modules/*.ts`
  Module-specific actions and reserved mutation endpoint definitions.

## Execution Notes

- Prefer the CLI instead of letting the model construct signed HTTP requests itself.
- The repository can ship prebuilt runtime files under `dist/`, so normal use should call `node dist/scripts/cli.js ...` directly without rebuilding first.
- Run `npm run build` only after changing TypeScript source files such as `plugin.ts` or `scripts/**/*.ts`.
- OpenClaw plugin loading should target the compiled entry at `dist/plugin.js`, not the TypeScript source file.
- If the OpenClaw runtime can execute TypeScript directly, import from [scripts/index.ts](scripts/index.ts) and call the module actions.
- If the runtime cannot execute TypeScript directly, use the TypeScript files as the source of truth for methods, paths, query parameters, and request payload shapes.
- The current implementation focuses on query and inspection actions; extend the reserved mutation definitions when you intentionally add managed write flows.

#!/usr/bin/env node

import { createHash } from 'node:crypto';

import { OnePanelClient } from './client.js';
import { getModule, listModules } from './index.js';

type Flags = Record<string, string | boolean>;

async function main(): Promise<void> {
  const args = process.argv.slice(2);
  const [command, ...rest] = args;

  if (!command || command === '--help' || command === '-h' || command === 'help') {
    printHelp();
    return;
  }

  switch (command) {
    case 'modules':
      handleModules();
      return;
    case 'actions':
      handleActions(rest);
      return;
    case 'sign':
      handleSign(rest);
      return;
    case 'request':
      await handleRequest(rest);
      return;
    case 'run':
      await handleRun(rest);
      return;
    default:
      throw new Error(`Unknown command: ${command}`);
  }
}

function printHelp(): void {
  console.log(`openclaw-1panel

Usage:
  openclaw-1panel modules
  openclaw-1panel actions <module>
  openclaw-1panel sign [--base-url URL] [--api-key KEY]
  openclaw-1panel request <METHOD> <PATH> [--body-json JSON] [--query-json JSON] [--node NODE]
  openclaw-1panel run <module> <action> [--input-json JSON] [--input-file FILE] [--node NODE]

Environment:
  ONEPANEL_BASE_URL
  ONEPANEL_API_KEY
  ONEPANEL_TIMEOUT_MS
  ONEPANEL_SKIP_TLS_VERIFY

Examples:
  openclaw-1panel modules
  openclaw-1panel actions monitoring
  openclaw-1panel request GET /api/v2/dashboard/base/os
  openclaw-1panel run monitoring getCurrentNode
  openclaw-1panel run websites searchWebsites --input-json '{"page":1,"pageSize":20}'
`);
}

function handleModules(): void {
  console.log(
    JSON.stringify(
      listModules().map((moduleDef) => ({
        id: moduleDef.id,
        title: moduleDef.title,
        description: moduleDef.description,
      })),
      null,
      2,
    ),
  );
}

function handleActions(args: string[]): void {
  const [moduleId] = args;
  if (!moduleId) {
    throw new Error('Missing module name');
  }
  const moduleDef = getRequiredModule(moduleId);
  console.log(
    JSON.stringify(
      {
        module: moduleDef.id,
        actions: Object.values(moduleDef.actions).map((action) => ({
          id: action.id,
          summary: action.summary,
          method: action.method,
          path: action.path,
          nodeAware: Boolean(action.nodeAware),
        })),
        reservedMutations: moduleDef.reservedMutations,
      },
      null,
      2,
    ),
  );
}

function handleSign(args: string[]): void {
  const { flags } = parseArgs(args);
  const config = resolveClientConfig(flags);
  const timestamp = `${Math.floor(Date.now() / 1000)}`;
  const token = computeToken(config.apiKey, timestamp);

  console.log(
    JSON.stringify(
      {
        baseUrl: config.baseUrl,
        headers: {
          '1Panel-Timestamp': timestamp,
          '1Panel-Token': token,
        },
      },
      null,
      2,
    ),
  );
}

async function handleRequest(args: string[]): Promise<void> {
  const [method, path, ...rest] = args;
  if (!method || !path) {
    throw new Error('Usage: request <METHOD> <PATH> [--body-json JSON] [--query-json JSON] [--node NODE]');
  }

  const { flags } = parseArgs(rest);
  const client = createClient(flags);
  const body = parseOptionalJson(flags['body-json']);
  const query = parseOptionalJson(flags['query-json']);
  const operateNode = readOptionalString(flags.node);

  const response = await client.request({
    method: method.toUpperCase() as 'GET' | 'POST' | 'PUT' | 'PATCH' | 'DELETE',
    path,
    body,
    query: isRecord(query) ? (query as Record<string, string | number | boolean | null | undefined>) : undefined,
    operateNode,
  });

  printResponse(response.status, response.data, response.rawBody);
}

async function handleRun(args: string[]): Promise<void> {
  const [moduleId, actionId, ...rest] = args;
  if (!moduleId || !actionId) {
    throw new Error('Usage: run <module> <action> [--input-json JSON] [--input-file FILE] [--node NODE]');
  }

  const { flags } = parseArgs(rest);
  const moduleDef = getRequiredModule(moduleId);
  const action = moduleDef.actions[actionId];
  if (!action) {
    throw new Error(`Unknown action "${actionId}" in module "${moduleId}"`);
  }

  const input = await loadInput(flags);
  const operateNode = readOptionalString(flags.node);
  const finalInput = mergeOperateNode(input, operateNode);
  const client = createClient(flags);
  const response = await action.execute(client, finalInput);

  printResponse(response.status, response.data, response.rawBody);
}

function parseArgs(args: string[]): { positionals: string[]; flags: Flags } {
  const positionals: string[] = [];
  const flags: Flags = {};

  for (let index = 0; index < args.length; index += 1) {
    const current = args[index];
    if (!current.startsWith('--')) {
      positionals.push(current);
      continue;
    }

    const key = current.slice(2);
    const next = args[index + 1];
    if (!next || next.startsWith('--')) {
      flags[key] = true;
      continue;
    }
    flags[key] = next;
    index += 1;
  }

  return { positionals, flags };
}

function resolveClientConfig(flags: Flags): { baseUrl: string; apiKey: string } {
  const baseUrl = readOptionalString(flags['base-url']) || process.env.ONEPANEL_BASE_URL;
  const apiKey = readOptionalString(flags['api-key']) || process.env.ONEPANEL_API_KEY;

  if (!baseUrl) {
    throw new Error('Missing ONEPANEL_BASE_URL or --base-url');
  }
  if (!apiKey) {
    throw new Error('Missing ONEPANEL_API_KEY or --api-key');
  }

  return { baseUrl, apiKey };
}

function createClient(flags: Flags): OnePanelClient {
  const config = resolveClientConfig(flags);
  return OnePanelClient.fromEnv({
    ...process.env,
    ONEPANEL_BASE_URL: config.baseUrl,
    ONEPANEL_API_KEY: config.apiKey,
  });
}

function computeToken(apiKey: string, timestamp: string): string {
  return createHash('md5').update(`1panel${apiKey}${timestamp}`).digest('hex');
}

async function loadInput(flags: Flags): Promise<unknown> {
  const inputFile = readOptionalString(flags['input-file']);
  const inputJson = readOptionalString(flags['input-json']);

  if (inputFile && inputJson) {
    throw new Error('Use only one of --input-file or --input-json');
  }

  if (inputFile) {
    const fs = await import('node:fs/promises');
    const content = await fs.readFile(inputFile, 'utf8');
    return JSON.parse(content);
  }

  if (inputJson) {
    return JSON.parse(inputJson);
  }

  return {};
}

function mergeOperateNode(input: unknown, operateNode?: string): unknown {
  if (!operateNode) {
    return input;
  }
  if (!isRecord(input)) {
    return { operateNode };
  }
  return {
    ...input,
    operateNode,
  };
}

function parseOptionalJson(value: string | boolean | undefined): unknown {
  const stringValue = readOptionalString(value);
  if (!stringValue) {
    return undefined;
  }
  return JSON.parse(stringValue);
}

function readOptionalString(value: string | boolean | undefined): string | undefined {
  return typeof value === 'string' ? value : undefined;
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null && !Array.isArray(value);
}

function getRequiredModule(moduleId: string) {
  const moduleDef = getModule(moduleId);
  if (!moduleDef) {
    throw new Error(`Unknown module: ${moduleId}`);
  }
  return moduleDef;
}

function printResponse(status: number, data: unknown, rawBody: string): void {
  const output = {
    status,
    ok: status >= 200 && status < 300,
    data,
  };

  console.log(JSON.stringify(output, null, 2));

  if (status >= 400) {
    if (!data && rawBody) {
      console.error(rawBody);
    }
    process.exitCode = 1;
  }
}

main().catch((error) => {
  console.error(
    JSON.stringify(
      {
        ok: false,
        error: error instanceof Error ? error.message : String(error),
      },
      null,
      2,
    ),
  );
  process.exit(1);
});

import { createHash } from 'node:crypto';
import http from 'node:http';
import https from 'node:https';

import type { OnePanelClientLike, OnePanelResponse, QueryValue, RequestOptions } from './types.js';

export interface OnePanelClientConfig {
  baseUrl: string;
  apiKey: string;
  timeoutMs?: number;
  skipTlsVerify?: boolean;
  defaultHeaders?: Record<string, string>;
}

export class OnePanelClient implements OnePanelClientLike {
  private readonly baseUrl: URL;
  private readonly apiKey: string;
  private readonly timeoutMs: number;
  private readonly skipTlsVerify: boolean;
  private readonly defaultHeaders: Record<string, string>;

  constructor(config: OnePanelClientConfig) {
    this.baseUrl = new URL(config.baseUrl);
    this.apiKey = config.apiKey;
    this.timeoutMs = config.timeoutMs ?? 30_000;
    this.skipTlsVerify = config.skipTlsVerify ?? false;
    this.defaultHeaders = config.defaultHeaders ?? {};
  }

  static fromEnv(env: Record<string, string | undefined>): OnePanelClient {
    const baseUrl = env.ONEPANEL_BASE_URL?.trim();
    const apiKey = env.ONEPANEL_API_KEY?.trim();
    if (!baseUrl) {
      throw new Error('Missing ONEPANEL_BASE_URL');
    }
    if (!apiKey) {
      throw new Error('Missing ONEPANEL_API_KEY');
    }

    return new OnePanelClient({
      baseUrl,
      apiKey,
      timeoutMs: Number.parseInt(env.ONEPANEL_TIMEOUT_MS || '30000', 10),
      skipTlsVerify: /^(1|true|yes)$/i.test(env.ONEPANEL_SKIP_TLS_VERIFY || ''),
    });
  }

  async request<T = unknown>(options: RequestOptions): Promise<OnePanelResponse<T>> {
    const url = this.buildUrl(options.path, options.query, options.operateNode);
    const body = options.body === undefined ? undefined : JSON.stringify(options.body);
    const headers = this.buildHeaders(body);
    const isHttps = url.protocol === 'https:';
    const transport = isHttps ? https : http;

    return new Promise<OnePanelResponse<T>>((resolve, reject) => {
      const request = transport.request(
        {
          protocol: url.protocol,
          hostname: url.hostname,
          port: url.port || (isHttps ? 443 : 80),
          path: `${url.pathname}${url.search}`,
          method: options.method,
          headers,
          rejectUnauthorized: !this.skipTlsVerify,
          timeout: this.timeoutMs,
        },
        (response) => {
          const chunks: Buffer[] = [];
          response.on('data', (chunk) => {
            chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
          });
          response.on('end', () => {
            const rawBody = Buffer.concat(chunks).toString('utf8');
            const normalizedHeaders = normalizeHeaders(response.headers);
            const data = parseResponseBody<T>(rawBody, normalizedHeaders['content-type']);
            resolve({
              status: response.statusCode ?? 0,
              headers: normalizedHeaders,
              data,
              rawBody,
            });
          });
        },
      );

      request.on('timeout', () => {
        request.destroy(new Error(`1Panel request timed out after ${this.timeoutMs}ms`));
      });
      request.on('error', reject);

      if (body !== undefined) {
        request.write(body);
      }
      request.end();
    });
  }

  private buildUrl(
    path: string,
    query?: Record<string, QueryValue>,
    operateNode?: string,
  ): URL {
    const normalizedPath = path.startsWith('/') ? path : `/${path}`;
    const url = new URL(normalizedPath, this.baseUrl);

    for (const [key, value] of Object.entries(query ?? {})) {
      if (value === undefined || value === null || value === '') {
        continue;
      }
      url.searchParams.set(key, String(value));
    }

    if (operateNode) {
      url.searchParams.set('operateNode', operateNode);
    }

    return url;
  }

  private buildHeaders(body?: string): Record<string, string> {
    const timestamp = `${Math.floor(Date.now() / 1000)}`;
    const token = createHash('md5')
      .update(`1panel${this.apiKey}${timestamp}`)
      .digest('hex');

    return {
      Accept: 'application/json, text/plain, text/event-stream',
      'Content-Type': 'application/json',
      '1Panel-Token': token,
      '1Panel-Timestamp': timestamp,
      'Content-Length': body ? `${Buffer.byteLength(body)}` : '0',
      ...this.defaultHeaders,
    };
  }
}

function normalizeHeaders(headers: http.IncomingHttpHeaders): Record<string, string> {
  const normalized: Record<string, string> = {};
  for (const [key, value] of Object.entries(headers)) {
    if (Array.isArray(value)) {
      normalized[key] = value.join(', ');
      continue;
    }
    if (value !== undefined) {
      normalized[key] = value;
    }
  }
  return normalized;
}

function parseResponseBody<T>(rawBody: string, contentType?: string): T {
  if (contentType?.includes('application/json')) {
    return JSON.parse(rawBody) as T;
  }

  try {
    return JSON.parse(rawBody) as T;
  } catch {
    return rawBody as T;
  }
}

